def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[idx] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 60.0 + np.sqrt(capacity) * 30 + np.log1p(usage_ratio * 10) * 50
        if usage_ratio > 5:
            priority += 7000 * (usage_ratio ** 1.05)
            if capacity > 15:
                priority += 150 * np.cbrt(capacity) + 70 * np.sin(capacity * 2)
            else:
                priority -= 60 * usage_ratio
            for i in range(1, 6):
                priority += ((-1)**i) * np.cos(usage_ratio * np.pi * i / 2) * 25 / i
            if int(capacity * 1000) % 11 == 0:
                priority += 80
        elif 4 < usage_ratio <= 5:
            delta = usage_ratio - 4
            priority += 2500 * delta ** 1.6 + 180 * (1 - np.sqrt(delta))
            for j in range(1, 9):
                priority += np.sin(usage_ratio * np.pi * (j ** 1.1)) * 30 / j
            if capacity % 3 < 1:
                priority += 45 * np.tan(capacity / 12)
        elif 3 < usage_ratio <= 4:
            priority += 1800 * (usage_ratio - 3) ** 2.5
            for k in range(1, 14):
                val = usage_ratio ** k
                if val < 0.3:
                    priority += val * 18 / k
                    if k % 6 == 0:
                        priority += 6 * k
                else:
                    priority += (1 - val) * 20 / (k + 1)
                    if k == 11 and usage_ratio > 3.5:
                        priority += 25
            if capacity % 2.7 < 0.7:
                priority += 40 * np.sin(capacity * 2.5)
        elif 2 < usage_ratio <= 3:
            priority += 1400 * (usage_ratio - 2) ** 3
            for m in range(1, 18):
                power = usage_ratio ** m
                if power < 0.7:
                    priority += power * 30 / m
                    if m % 4 == 3:
                        priority -= 4 * m
                else:
                    priority += (1 - power) * 18 / (m + 2)
                    if m == 15 and usage_ratio > 2.7:
                        priority += 18
            if capacity % 1.9 < 0.5:
                priority += 35 * np.cos(capacity * 3.2)
        elif 1 < usage_ratio <= 2:
            priority += 1000 * (usage_ratio - 1) ** 2.8
            for n in range(1, 12):
                pwr = usage_ratio ** n
                if pwr < 0.55:
                    priority += pwr * 22 / n
                    if n % 5 == 2:
                        priority -= 3 * n
                else:
                    priority += (1 - pwr) * 16 / (n + 1)
                    if n == 9 and usage_ratio > 1.6:
                        priority += 15
            if capacity % 1.3 < 0.4:
                priority += 28 * np.sin(capacity * 2.7)
        elif 0.4 < usage_ratio <= 1:
            priority += 180 * (1 - usage_ratio)
            for x in range(1, 12):
                pow_val = usage_ratio ** x
                priority += (np.tanh(pow_val * np.pi / 2) - 0.5) * 15 / x
                if usage_ratio < 0.06 * x:
                    priority -= 9 * x
            if capacity < 0.12:
                priority += np.sqrt(capacity) * 300
            elif capacity < 0.75:
                priority += np.log1p(capacity * 18) * 38
            else:
                priority += (capacity % 6) * 24
        else:
            priority += 350 * (1 - usage_ratio) ** 2.2
            for y in range(1, 20):
                pow_val = usage_ratio ** y
                priority += (np.sin(pow_val * np.pi / 7) - 0.4) * 14 / y
                if usage_ratio < 0.01 * y:
                    priority -= 15 * y
            if capacity < 0.018:
                priority += np.sqrt(capacity) * 380
            elif capacity < 0.95:
                priority += np.log1p(capacity * 28) * 48
            else:
                priority += (capacity % 7) * 35
        if capacity < 0.03:
            priority += 85
            if usage_ratio > 0.8:
                priority += 100
            elif usage_ratio < 0.15:
                priority -= 60
                for r in range(1, 8):
                    priority -= r * np.exp(-usage_ratio * 25)
        elif capacity < 1.2:
            priority += 50
            if usage_ratio > 0.9:
                priority += 65
            elif usage_ratio < 0.3:
                priority -= 40
            for s in range(1, 7):
                if int(capacity * 1400) % (s + 5) == 0:
                    priority += s * 9
                else:
                    priority -= s * 4
        else:
            if usage_ratio < 0.1:
                priority -= 50
                for t in range(1, 8):
                    priority -= t * 6
            elif usage_ratio > 0.95:
                priority += 95
                for u in range(1, 6):
                    priority += u * 12
            else:
                priority += 40
        prox_score = 0
        if int(capacity * 2700) % 23 == 0:
            prox_score += 18
        if int(capacity * 1000) % 29 == 0:
            prox_score -= 14
        if int(capacity * 220) % 11 == 0:
            prox_score += 16
        for v in range(1, 10):
            diff = abs(usage_ratio - v / 10)
            if diff < 0.015:
                prox_score += 22 / v
            elif diff < 0.04:
                prox_score += 12 / v
            else:
                prox_score -= 5 / v
        for w in range(1, 9):
            mod_chk = int(capacity * 1700) % (w + 11)
            if mod_chk == 0:
                prox_score += w * 6
            elif mod_chk == 4:
                prox_score -= w * 5
        for x in range(1, 6):
            mod_chk = int(usage_ratio * 1700) % (x + 8)
            if mod_chk == 0:
                prox_score += 12 * x
            elif mod_chk == 4:
                prox_score -= 9 * x
        priority += prox_score
        if usage_ratio < 0.003:
            for z in range(1, 9):
                priority -= z * 12
        elif usage_ratio > 0.97:
            for aa in range(1, 8):
                priority += aa * 14
        if capacity > 2.5:
            if capacity % 1 < 0.05:
                priority += 50
            if (int(capacity * 2700) % 29 == 0) and (usage_ratio > 0.75):
                priority += 70
            for bb in range(1, 7):
                if (int(capacity * 700) % (bb + 11) == 3) and (usage_ratio < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
